    fs: Option<&mut FuncState>,
    n: &GcRef<LuaString>,
    var: &mut ExprDesc,
    base: bool,
) -> Result<(), LuaError> {
    match fs {
        None => {
            // C: init_exp(var, VVOID, 0) — default is global
            init_exp(var, ExprKind::Void, 0);
