    pub value: i32,
    // C: struct transferinfo { unsigned short ftransfer, ntransfer }
    pub ftransfer: u16,
    pub ntransfer: u16,
}

impl CallInfoFrame {
    /// Default C-call frame (no continuation, zero context).
    pub fn c_default() -> Self {
